USE amz_user;
CREATE TABLE IF NOT EXISTS amz_user (id BIGINT AUTO_INCREMENT PRIMARY KEY, username VARCHAR(50) NOT NULL UNIQUE, password VARCHAR(255) NOT NULL, nickname VARCHAR(50) DEFAULT '', image VARCHAR(500) DEFAULT '', mail VARCHAR(100) DEFAULT '', phone VARCHAR(20) DEFAULT '', sex TINYINT DEFAULT 0, birthday VARCHAR(20) DEFAULT '', address VARCHAR(200) DEFAULT '', create_time DATETIME DEFAULT CURRENT_TIMESTAMP, update_time DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS amz_attention (id BIGINT AUTO_INCREMENT PRIMARY KEY, user_id BIGINT NOT NULL, attention_id BIGINT NOT NULL, create_time DATETIME DEFAULT CURRENT_TIMESTAMP, UNIQUE KEY uk_user_attention (user_id, attention_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
